import { Injectable, signal, computed } from '@angular/core';

/**
 * CounterService — a simple service demonstrating:
 *  - @Injectable decorator
 *  - providedIn: 'root' for app-wide singleton
 *  - signal() for reactive shared state
 *  - computed() for derived state
 *  - Public methods as the API surface
 */
@Injectable({
  providedIn: 'root',   // singleton — one instance for the whole app
})
export class CounterService {
  // Private signal — only this service can write to it
  private _count = signal(0);

  // Public read-only signal — components read but cannot mutate directly
  readonly count   = this._count.asReadonly();
  readonly doubled = computed(() => this._count() * 2);
  readonly isZero  = computed(() => this._count() === 0);

  // Public API — the only way to change the state
  increment(): void { this._count.update(n => n + 1); }
  decrement(): void { this._count.update(n => n - 1); }
  reset():     void { this._count.set(0); }
  addBy(n: number): void { this._count.update(c => c + n); }
}

import { Component, inject, computed } from '@angular/core';
import { CounterService } from './counter.service';
import { UserService }    from './user.service';
import { ThemeService }   from './theme.service';

// ── ✓ Modern: inject() at field level ────────────────────
@Component({
  selector: 'app-dashboard',
  standalone: true,
  template: `
    <h1>Welcome, {{ user.name() }}</h1>
    <p>Count: {{ counter.count() }}</p>
    <p>Theme: {{ theme.isDark() ? 'Dark' : 'Light' }}</p>
  `,
})
export class DashboardComponent {
  // Each dependency on its own line — readable, no constructor needed
  counter = inject(CounterService);
  user    = inject(UserService);
  theme   = inject(ThemeService);

  // Can use injected services immediately in computed()
  summary = computed(() =>
    `${this.user.name()} has count ${this.counter.count()}`
  );
}

