// ── Both result in exactly the same behaviour ─────────────
// Angular's DI system provides the same singleton instance either way.

import { Injectable, signal, computed, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { catchError, EMPTY } from 'rxjs';

export interface User {
  id:     number;
  name:   string;
  email:  string;
  role:   'admin' | 'user' | 'guest';
}

@Injectable({ providedIn: 'root' })
export class UserService {
  private http = inject(HttpClient);  // inject another service inside a service!

  // ── State signals (private write, public read) ─────────
  private _users     = signal<User[]>([]);
  private _loading   = signal(false);
  private _error     = signal<string | null>(null);
  private _currentId = signal<number | null>(null);

  // ── Public read-only access ────────────────────────────
  readonly users    = this._users.asReadonly();
  readonly loading  = this._loading.asReadonly();
  readonly error    = this._error.asReadonly();

  // ── Derived / computed signals ─────────────────────────
  readonly count      = computed(() => this._users().length);
  readonly admins     = computed(() => this._users().filter(u => u.role === 'admin'));
  readonly current    = computed(() =>
    this._users().find(u => u.id === this._currentId()) ?? null
  );
  readonly hasError   = computed(() => this._error() !== null);

  // ── Methods (the public API) ───────────────────────────
  loadUsers(): void {
    this._loading.set(true);
    this._error.set(null);

    this.http.get<User[]>('https://jsonplaceholder.typicode.com/users')
      .pipe(
        catchError(err => {
          this._error.set('Failed to load users: ' + err.message);
          this._loading.set(false);
          return EMPTY;
        })
      )
      .subscribe(users => {
        this._users.set(users);
        this._loading.set(false);
      });
  }

  selectUser(id: number): void {
    this._currentId.set(id);
  }

  addUser(user: Omit<User, 'id'>): void {
    const newUser = { ...user, id: Date.now() };
    this._users.update(list => [...list, newUser]);
  }

  removeUser(id: number): void {
    this._users.update(list => list.filter(u => u.id !== id));
  }
}

import { Component, inject, OnInit } from '@angular/core';
import { UserService } from './user.service';

@Component({
  selector: 'app-users-page',
  standalone: true,
  template: `
    <h1>Users ({{ userService.count() }})</h1>

    <!-- Read signals directly in the template -->
    @if (userService.loading()) {
      <p>Loading...</p>
    } @else if (userService.hasError()) {
      <p class="error">{{ userService.error() }}</p>
      <button (click)="userService.loadUsers()">Retry</button>
    } @else {
      @for (user of userService.users(); track user.id) {
        <div (click)="userService.selectUser(user.id)">
          <strong>{{ user.name }}</strong> — {{ user.role }}
          <button (click)="userService.removeUser(user.id)">Remove</button>
        </div>
      } @empty {
        <p>No users loaded yet.</p>
      }
    }

    <!-- Selected user detail -->
    @if (userService.current(); as user) {
      <div class="detail">
        <h2>{{ user.name }}</h2>
        <p>{{ user.email }}</p>
      </div>
    }
  `,
})
export class UsersPageComponent implements OnInit {
  userService = inject(UserService);

  ngOnInit(): void {
    this.userService.loadUsers();   // trigger the HTTP call
  }
}

