import { Injectable, signal, computed, inject, effect } from '@angular/core';
import { UserService } from './user.service';
import { HttpClient }  from '@angular/common/http';

export interface CartItem {
  productId: number;
  name:      string;
  price:     number;
  qty:       number;
}

@Injectable({ providedIn: 'root' })
export class CartService {
  // Inject another service and HttpClient
  private userService = inject(UserService);
  private http        = inject(HttpClient);

  private _items = signal<CartItem[]>([]);

  readonly items      = this._items.asReadonly();
  readonly itemCount  = computed(() =>
    this._items().reduce((sum, i) => sum + i.qty, 0)
  );
  readonly total      = computed(() =>
    this._items().reduce((sum, i) => sum + i.price * i.qty, 0)
  );
  readonly isEmpty    = computed(() => this._items().length === 0);

  constructor() {
    // effect() — reload cart when user changes
    effect(() => {
      const user = this.userService.current();
      if (user) this.loadCart(user.id);
      else      this._items.set([]);   // clear on logout
    });
  }

  addItem(item: CartItem): void {
    this._items.update(list => {
      const existing = list.find(i => i.productId === item.productId);
      if (existing) {
        return list.map(i =>
          i.productId === item.productId
            ? { ...i, qty: i.qty + 1 }
            : i
        );
      }
      return [...list, { ...item, qty: 1 }];
    });
  }

  removeItem(productId: number): void {
    this._items.update(list => list.filter(i => i.productId !== productId));
  }

  clear(): void { this._items.set([]); }

  private loadCart(userId: number): void {
    // Load saved cart for this user
    this.http.get<CartItem[]>(`/api/cart/${userId}`)
      .subscribe(items => this._items.set(items));
  }
}

import { Injectable, Component, signal, inject } from '@angular/core';

// ── Service with no providedIn ────────────────────────────
// Must be explicitly provided — not a global singleton
@Injectable()
export class WizardStateService {
  currentStep = signal(1);
  totalSteps  = signal(5);
  formData    = signal<Record<string, unknown>>({});

  next(): void { this.currentStep.update(s => Math.min(s + 1, this.totalSteps())); }
  back(): void { this.currentStep.update(s => Math.max(s - 1, 1)); }
  saveStep(data: Record<string, unknown>): void {
    this.formData.update(d => ({ ...d, ...data }));
  }
}

// ── Parent component PROVIDES the service ────────────────
@Component({
  selector: 'app-wizard',
  standalone: true,
  imports: [/* WizardStep1, WizardStep2 ... */],
  // providers:[] creates a NEW instance for this component + children
  providers: [WizardStateService],
  template: `
    <div class="wizard">
      <p>Step {{ state.currentStep() }} of {{ state.totalSteps() }}</p>
      <!-- child step components also get this same WizardStateService instance -->
    </div>
  `,
})
export class WizardComponent {
  state = inject(WizardStateService);  // gets the instance from providers:[]
}

// ── If you render TWO wizards, each gets its OWN WizardStateService ──
